            if shape.top < min_top:
                title_shape, min_top = shape, shape.top

        if shape.is_placeholder and shape.placeholder_format.type == 1:  # 1 corresponds to a TITLE placeholder
            title_shape = shape
            break

    if not title_shape:
        return ("Could not find title shape on slide 1.", 0.0)
