def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    slide = prs.slides[0]
    title_shape, min_top = None, float('inf')
    for shape in slide.shapes:
        if shape.has_text_frame and shape.text_frame.text.strip():
            if shape.top < min_top:
                title_shape, min_top = shape, shape.top

            if shape.is_placeholder and shape.placeholder_format.type == 1:  # TITLE
                title_shape = shape
                break
    if not title_shape:
        return ("Could not find title shape on slide 1.", 0.0)
    tf = title_shape.text_frame
    all_bold = True
    for para in tf.paragraphs:
        for run in para.runs:
            # None means inherit, but for title, we expect explicit bold
            if not run.font.bold:
                all_bold = False
    if all_bold:
        return ("Title text is fully bolded.", 1.0)
    else:
        return ("Not all title text is bolded.", 0.0)

def compute_score() -> tuple[str, float]:
    # Only allow the title text to change, and its formatting to bold.
    # Check ppt_diff for other modifications on slide 1
    slide1_mods = []
    slide1_id = None
    for slide in ppt_diff.modified_slides:
        # Find slide 1 by number
        orig, mod = slide
        if orig.slide_number == 1:
            slide1_id = orig.slide_id
            slide1_mods.append((orig, mod))
    # If slide1_id is not found, check for removal/addition
    if not slide1_id:
        for slide in ppt_diff.removed_slides:
            if slide.slide_number == 1:
                return ("Slide 1 was removed.", 0.0)
        for slide in ppt_diff.added_slides:
            if slide.slide_number == 1:
                return ("A new Slide 1 was added (should only be edited).", 0.0)
        # If no changes to slide 1, that's fine
        return ("No extraneous changes to Slide 1.", 1.0)
    # Now check for element additions/removals/other changes on slide 1
    # Check animations, transitions as well
    for anim in ppt_diff.added_animations + ppt_diff.removed_animations:
        if anim.slide_id == slide1_id:
            return ("Extraneous animation changes on Slide 1.", 0.0)
    for trans in ppt_diff.added_transitions + ppt_diff.removed_transitions:
        if trans.slide_id == slide1_id:
            return ("Extraneous transition changes on Slide 1.", 0.0)
    # Check for changes to non-title shapes
    from pptx import Presentation
    orig_prs = Presentation(original_ppt_path)
    mod_prs = Presentation(modified_ppt_path)
    orig_slide = orig_prs.slides[0]
    mod_slide = mod_prs.slides[0]
    # Compare all shapes except the title placeholder
    def get_shapes(slide):
        title_shape_idx, min_top = -1, float('inf')
        for i, shape in enumerate(slide.shapes):
            if hasattr(shape, 'text_frame'):
                if shape.top < min_top:
                    title_shape_idx, min_top = i, shape.top

                if shape.is_placeholder and shape.placeholder_format.type == 1:  # TITLE
                    title_shape_idx = i
                    break
        return [(s.shape_id, s.text if hasattr(s, 'text') else None, i == title_shape_idx, s) for i, s in enumerate(slide.shapes)]
    orig_shapes = get_shapes(orig_slide)
    mod_shapes = get_shapes(mod_slide)
    for o, m in zip(orig_shapes, mod_shapes):
        o_id, o_text, o_is_title, o_shape = o
        m_id, m_text, m_is_title, m_shape = m
        # Only compare non-title shapes
        if not o_is_title:
            # If the text is changed, that's extraneous
            if o_text != m_text:
                return ("Non-title text was modified on Slide 1.", 0.0)
    return ("No extraneous changes to Slide 1.", 1.0)

def compute_score() -> tuple[str, float]:
    # Check ppt_diff for changes to any slide except slide 1
    for slide in ppt_diff.modified_slides:
        orig, mod = slide
        if orig.slide_number != 1:
            return (f"Slide {orig.slide_number} was modified, but only Slide 1 should be changed.", 0.0)
    for slide in ppt_diff.added_slides:
        if slide.slide_number != 1:
            return (f"Slide {slide.slide_number} was added, but only Slide 1 should be changed.", 0.0)
    for slide in ppt_diff.removed_slides:
        if slide.slide_number != 1:
            return (f"Slide {slide.slide_number} was removed, but only Slide 1 should be changed.", 0.0)
    return ("No changes to other slides.", 1.0)
